import java.util.*;

public class Solution {
    public static long solve(long[][] edges, boolean[] online, long k) {
        int n = online.length;
        if (n == 0) return -1;

        long maxEdge = 0;
        for (long[] e : edges) {
            if (e[2] > maxEdge) maxEdge = e[2];
        }

        long low = 0;
        long high = maxEdge + 1;

        while (low < high) {
            long mid = low + (high - low) / 2;
            if (check(mid, edges, online, n, k)) {
                low = mid + 1;
            } else {
                high = mid;
            }
        }

        long ans = low - 1;
        if (ans < 0) return -1;
        return ans;
    }

    static boolean check(long x, long[][] edges, boolean[] online, int n, long k) {
        long INF = Long.MAX_VALUE / 2;
        List<long[]>[] graph = new ArrayList[n];
        for (int i = 0; i < n; i++) {
            graph[i] = new ArrayList<>();
        }
        int[] inDegree = new int[n];
        long[] minCost = new long[n];
        Arrays.fill(minCost, INF);
        minCost[0] = 0;

        for (long[] e : edges) {
            int u = (int) e[0];
            int v = (int) e[1];
            long costVal = e[2];

            if (v == 0) continue;
            if (!online[u] || !online[v]) continue;
            if (costVal < x) continue;

            graph[u].add(new long[]{v, costVal});
            inDegree[v]++;
        }

        Queue<Integer> q = new LinkedList<>();
        for (int i = 0; i < n; i++) {
            if (online[i] && inDegree[i] == 0) {
                q.add(i);
            }
        }

        while (!q.isEmpty()) {
            int u = q.poll();
            for (long[] next : graph[u]) {
                int v = (int) next[0];
                long w = next[1];
                if (minCost[u] + w < minCost[v]) {
                    minCost[v] = minCost[u] + w;
                }
                inDegree[v]--;
                if (inDegree[v] == 0) {
                    q.add(v);
                }
            }
        }

        return minCost[n-1] <= k;
    }
}
